"""Tests for DeepLake Managed Service Client.

Covers:
- Client initialization
- Token parsing / org_id extraction
- _get_root_path() from API
- _get_dataset_path() using root_path
- Database proxy and db property
- ManagedQueryBuilder (select, where, order_by, limit, offset, _build_sql)
- ManagedQueryBuilder.execute()
- Normalizer dispatching (_normalize_files routes by extension)
- Individual normalizers: image, text, pdf, binary, video (pure data transforms)
- Dict normalization (_normalize_dict with batching)
- _write_batches (single writer)
- _ensure_columns (schema setup + inference)
- Text chunking (_chunk_text)
- Top-level ingest()
- query() via API
- list_tables(), drop_table() via API
- Error cases
"""

from __future__ import annotations

import base64
import json
import os
from pathlib import Path
from typing import Any, Dict, List, Optional
from unittest.mock import MagicMock, Mock, patch

import pytest

from .client import Client, Database, ManagedQueryBuilder
from .errors import (
    AuthError,
    CredentialsError,
    IngestError,
    ManagedServiceError,
    TableError,
    TokenError,
    WorkspaceError,
)


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _make_token(claims: dict) -> str:
    """Build a fake JWT with the given payload claims."""
    header = base64.urlsafe_b64encode(b'{"alg":"HS256"}').rstrip(b"=").decode()
    payload = base64.urlsafe_b64encode(json.dumps(claims).encode()).rstrip(b"=").decode()
    sig = base64.urlsafe_b64encode(b"fakesig").rstrip(b"=").decode()
    return f"{header}.{payload}.{sig}"


def _make_client(
    token_claims: Optional[dict] = None,
    workspace_id: str = "test-ws",
    api_url: str = "http://localhost:8080",
) -> Client:
    """Create a Client with a synthetic token, bypassing real API calls."""
    claims = token_claims or {"OrgID": "org-123", "UserID": "u1"}
    token = _make_token(claims)
    return Client(token=token, workspace_id=workspace_id, api_url=api_url)


# Fake deeplake dataset for ingestion tests
class FakeColumn:
    def __init__(self, name):
        self.name = name


class FakeSchema:
    def __init__(self, col_names=None):
        self.columns = [FakeColumn(n) for n in (col_names or [])]


class FakeDataset:
    def __init__(self, col_names=None):
        self.schema = FakeSchema(col_names)
        self.appended = []
        self.committed = False
        self._columns_added = []

    def add_column(self, name, dtype):
        self.schema.columns.append(FakeColumn(name))
        self._columns_added.append((name, dtype))

    def append(self, data):
        self.appended.append(data)

    def commit(self):
        self.committed = True


