class TestClientInit:
    def test_init_extracts_org_id_from_token(self):
        client = _make_client({"OrgID": "my-org", "UserID": "u1"})
        assert client.org_id == "my-org"

    def test_init_extracts_org_id_lowercase(self):
        client = _make_client({"org_id": "lower-org"})
        assert client.org_id == "lower-org"

    def test_init_no_org_id_or_data_dir_params(self):
        """Verify org_id and data_dir are not accepted as constructor args."""
        import inspect
        sig = inspect.signature(Client.__init__)
        param_names = set(sig.parameters.keys()) - {"self"}
        assert "org_id" not in param_names
        assert "data_dir" not in param_names

    def test_init_accepted_params(self):
        """Verify the constructor only accepts token, workspace_id, api_url."""
        import inspect
        sig = inspect.signature(Client.__init__)
        param_names = set(sig.parameters.keys()) - {"self"}
        assert param_names == {"token", "workspace_id", "api_url"}

    def test_init_requires_token(self):
        # Clear env to avoid fallback
        with patch.dict(os.environ, {}, clear=True):
            with pytest.raises(AuthError, match="Token required"):
                Client()

    def test_init_workspace_defaults_to_default(self):
        """workspace_id defaults to 'default' when not provided."""
        token = _make_token({"OrgID": "org"})
        with patch.dict(os.environ, {}, clear=True):
            client = Client(token=token)
            assert client.workspace_id == "default"

    def test_init_token_from_env(self):
        """Token falls back to DEEPLAKE_API_KEY env var."""
        token = _make_token({"OrgID": "org"})
        with patch.dict(os.environ, {"DEEPLAKE_API_KEY": token}, clear=True):
            client = Client()
            assert client.token == token
            assert client.workspace_id == "default"

    def test_init_token_required(self):
        with patch.dict(os.environ, {}, clear=True):
            with pytest.raises(AuthError, match="Token required"):
                Client(workspace_id="env-ws")

    def test_init_explicit_api_url(self):
        token = _make_token({"OrgID": "env-org"})
        client = Client(token=token, workspace_id="env-ws", api_url="http://custom:9090")
        assert client.org_id == "env-org"
        assert client.workspace_id == "env-ws"
        assert client.api_url == "http://custom:9090"

    def test_init_default_api_url(self):
        token = _make_token({"OrgID": "org"})
        c = Client(token=token, workspace_id="ws")
        assert c.api_url == "https://api.deeplake.ai"

    def test_init_strips_trailing_slash_from_api_url(self):
        token = _make_token({"OrgID": "org"})
        c = Client(token=token, workspace_id="ws", api_url="http://host:8080/")
        assert c.api_url == "http://host:8080"


# ============================================================================
# Token Parsing
# ============================================================================


class TestTokenParsing:
    def test_invalid_token_format(self):
        with pytest.raises(TokenError, match="expected JWT with 3 parts"):
            Client(token="not-a-jwt", workspace_id="ws")

    def test_token_without_org_id_falls_back_to_api(self):
        token = _make_token({"UserID": "u1"})  # no OrgID
        with patch.object(Client, "_fetch_org_id_from_api", return_value="api-org"):
            c = Client(token=token, workspace_id="ws")
            assert c.org_id == "api-org"

    def test_token_without_org_id_api_fallback_fails(self):
        token = _make_token({"UserID": "u1"})
        with patch.object(Client, "_fetch_org_id_from_api", return_value=None):
            with pytest.raises(TokenError, match="does not contain org_id"):
                Client(token=token, workspace_id="ws")

    def test_corrupted_payload_raises_token_error(self):
        # Mangled base64 in payload
        header = base64.urlsafe_b64encode(b'{"alg":"HS256"}').rstrip(b"=").decode()
        sig = base64.urlsafe_b64encode(b"sig").rstrip(b"=").decode()
        with pytest.raises(TokenError):
            Client(token=f"{header}.!!!invalid!!!.{sig}", workspace_id="ws")


