class TestGetRootPath:
    def test_fetches_from_api(self):
        client = _make_client()
        client._api_request = Mock(return_value={"storage_path": "s3://bucket/org-123"})

        result = client._get_root_path()
        assert result == "s3://bucket/org-123"
        client._api_request.assert_called_once_with(
            "GET", "/workspaces/test-ws/storage-path"
        )

    def test_caches_root_path(self):
        client = _make_client()
        client._api_request = Mock(return_value={"storage_path": "/data/org"})

        first = client._get_root_path()
        second = client._get_root_path()
        assert first == second
        # Only one API call
        assert client._api_request.call_count == 1

    def test_raises_on_empty_response(self):
        client = _make_client()
        client._api_request = Mock(return_value={})

        with pytest.raises(WorkspaceError, match="No storage path"):
            client._get_root_path()

    def test_raises_on_api_failure(self):
        client = _make_client()
        client._api_request = Mock(side_effect=ManagedServiceError("API down"))

        with pytest.raises(ManagedServiceError):
            client._get_root_path()


