# ============================================================================
# ManagedQueryBuilder
# ============================================================================


class TestManagedQueryBuilder:
    def _builder(self, table="videos", workspace_id="test-ws"):
        client = _make_client(workspace_id=workspace_id)
        return ManagedQueryBuilder(client, table)

    # -- _build_sql --

    def test_default_select_star(self):
        sql, params = self._builder()._build_sql()
        assert sql == 'SELECT * FROM "videos"'
        assert params is None

    def test_select_specific_columns(self):
        sql, params = self._builder().select("id", "text")._build_sql()
        assert sql == 'SELECT id, text FROM "videos"'
        assert params is None

    def test_single_where(self):
        sql, params = self._builder().where("id = $1", "abc")._build_sql()
        assert "WHERE id = $1" in sql
        assert params == ["abc"]

    def test_multiple_where_anded(self):
        b = self._builder().where("a = $1", 1).where("b = $2", 2)
        sql, params = b._build_sql()
        assert "WHERE a = $1 AND b = $2" in sql
        assert params == [1, 2]

    def test_where_no_params(self):
        sql, params = self._builder().where("active = true")._build_sql()
        assert "WHERE active = true" in sql
        # No params collected -> returns None
        assert params is None

    def test_order_by(self):
        sql, _ = self._builder().order_by("created_at DESC")._build_sql()
        assert "ORDER BY created_at DESC" in sql

    def test_multiple_order_by(self):
        b = self._builder().order_by("a ASC").order_by("b DESC")
        sql, _ = b._build_sql()
        assert "ORDER BY a ASC, b DESC" in sql

    def test_limit(self):
        sql, _ = self._builder().limit(10)._build_sql()
        assert "LIMIT 10" in sql

    def test_offset(self):
        sql, _ = self._builder().offset(20)._build_sql()
        assert "OFFSET 20" in sql

    def test_full_chain(self):
        b = (
            self._builder()
            .select("id", "text")
            .where("file_id = $1", "f1")
            .where("score > $2", 0.5)
            .order_by("score DESC")
            .limit(10)
            .offset(5)
        )
        sql, params = b._build_sql()
        assert sql == (
            'SELECT id, text FROM "videos" '
            "WHERE file_id = $1 AND score > $2 "
            "ORDER BY score DESC "
            "LIMIT 10 "
            "OFFSET 5"
        )
        assert params == ["f1", 0.5]

    def test_escapes_double_quotes_in_table(self):
        b = self._builder(table='my"table')
        sql, _ = b._build_sql()
        assert '"my""table"' in sql

    # -- chaining returns self --

    def test_select_returns_self(self):
        b = self._builder()
        assert b.select("a") is b

    def test_where_returns_self(self):
        b = self._builder()
        assert b.where("x = 1") is b

    def test_order_by_returns_self(self):
        b = self._builder()
        assert b.order_by("x") is b

    def test_limit_returns_self(self):
        b = self._builder()
        assert b.limit(1) is b

    def test_offset_returns_self(self):
        b = self._builder()
        assert b.offset(1) is b

    # -- execute / __call__ --

    def test_execute_delegates_to_client_query(self):
        client = _make_client()
        client.query = Mock(return_value=[{"id": 1}])
        b = ManagedQueryBuilder(client, "t").select("id").limit(5)
        result = b.execute()
        assert result == [{"id": 1}]
        client.query.assert_called_once()
        sql_arg, params_arg = client.query.call_args[0]
        assert "SELECT id" in sql_arg
        assert "LIMIT 5" in sql_arg

    def test_call_is_alias_for_execute(self):
        client = _make_client()
        client.query = Mock(return_value=[])
        b = ManagedQueryBuilder(client, "t")
        assert b() == []
        client.query.assert_called_once()

    def test_repr(self):
        b = self._builder().select("id").where("x = %s", 1).limit(5)
        r = repr(b)
        assert "ManagedQueryBuilder" in r
        assert "SELECT id" in r


