class TestRawQuery:
    def test_query_returns_dicts(self):
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["id", "text"],
            "rows": [["r1", "hello"], ["r2", "world"]],
            "row_count": 2,
        })

        rows = client.query("SELECT id, text FROM t")
        assert len(rows) == 2
        assert rows[0] == {"id": "r1", "text": "hello"}
        assert rows[1] == {"id": "r2", "text": "world"}

        client._api_request.assert_called_once_with(
            "POST",
            "/workspaces/test-ws/tables/query",
            json_data={"query": "SELECT id, text FROM t"},
            timeout=60,
        )

    def test_query_with_params(self):
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["id"],
            "rows": [["r1"]],
            "row_count": 1,
        })

        client.query("SELECT id FROM t WHERE id = $1", ("r1",))
        client._api_request.assert_called_once_with(
            "POST",
            "/workspaces/test-ws/tables/query",
            json_data={"query": "SELECT id FROM t WHERE id = $1", "params": ["r1"]},
            timeout=60,
        )

    def test_query_raises_table_error(self):
        client = _make_client()
        client._api_request = Mock(side_effect=ManagedServiceError("bad sql"))

        with pytest.raises(TableError, match="Query failed"):
            client.query("BAD SQL")


# ============================================================================
# Text chunking
# ============================================================================


class TestChunkText:
    def _chunk(self, text, size=100, overlap=20):
        client = _make_client()
        return client._chunk_text(text, size, overlap)

    def test_short_text_returns_single_chunk(self):
        chunks = self._chunk("Hello world", size=100)
        assert chunks == ["Hello world"]

    def test_empty_text_returns_empty(self):
        assert self._chunk("", size=100) == []
        assert self._chunk("   ", size=100) == []

    def test_splits_long_text(self):
        text = "A" * 250
        chunks = self._chunk(text, size=100, overlap=20)
        assert len(chunks) >= 2
        # All content is covered
        joined = "".join(chunks)
        assert len(joined) >= 250

    def test_sentence_boundary_splitting(self):
        text = "First sentence. Second sentence. Third sentence. Fourth sentence end."
        chunks = self._chunk(text, size=40, overlap=5)
        assert len(chunks) >= 2
        # Should split near sentence boundaries
        assert any("." in c for c in chunks)

    def test_no_infinite_loop_on_no_boundary(self):
        """Ensure chunking terminates even without sentence boundaries."""
        text = "x" * 500
        chunks = self._chunk(text, size=100, overlap=50)
        assert len(chunks) >= 2
        total_unique = sum(len(c) for c in chunks)
        assert total_unique > 0


# ============================================================================
# Normalizer Dispatching (_normalize_files)
# ============================================================================


class TestNormalizeFiles:
    def _client_with_normalize_mocks(self):
        client = _make_client()
        # Use side_effect so each call returns a fresh iterator for generators
        client._normalize_video = Mock(side_effect=lambda p: iter([{"id": ["v"]}]))
        client._normalize_image = Mock(side_effect=lambda p: {"id": ["i"]})
        client._normalize_pdf = Mock(side_effect=lambda p: iter([{"id": ["p"]}]))
        client._normalize_text = Mock(side_effect=lambda p, cs, co: {"id": ["t"]})
        client._normalize_binary = Mock(side_effect=lambda p: {"id": ["b"]})
        return client

    def test_routes_video_extensions(self, tmp_path):
        client = self._client_with_normalize_mocks()
        for ext in [".mp4", ".mov", ".avi", ".mkv", ".webm"]:
            f = tmp_path / f"file{ext}"
            f.write_bytes(b"\x00")
            list(client._normalize_files([str(f)], 1000, 200))
        assert client._normalize_video.call_count == 5

    def test_routes_image_extensions(self, tmp_path):
        client = self._client_with_normalize_mocks()
        for ext in [".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp"]:
            f = tmp_path / f"file{ext}"
            f.write_bytes(b"\x00")
            list(client._normalize_files([str(f)], 1000, 200))
        assert client._normalize_image.call_count == 6

    def test_routes_pdf(self, tmp_path):
        client = self._client_with_normalize_mocks()
        f = tmp_path / "doc.pdf"
        f.write_bytes(b"\x00")
        list(client._normalize_files([str(f)], 1000, 200))
        client._normalize_pdf.assert_called_once()

    def test_routes_text_extensions(self, tmp_path):
        client = self._client_with_normalize_mocks()
        for ext in [".txt", ".md", ".json", ".csv", ".xml", ".html"]:
            f = tmp_path / f"file{ext}"
            f.write_bytes(b"\x00")
            list(client._normalize_files([str(f)], 1000, 200))
        assert client._normalize_text.call_count == 6

    def test_routes_unknown_to_binary(self, tmp_path):
        client = self._client_with_normalize_mocks()
        f = tmp_path / "data.xyz"
        f.write_bytes(b"\x00")
        list(client._normalize_files([str(f)], 1000, 200))
        client._normalize_binary.assert_called_once()

    def test_missing_file_raises_ingest_error(self):
        client = self._client_with_normalize_mocks()
        with pytest.raises(IngestError, match="File not found"):
            list(client._normalize_files(["/no/such/file.txt"], 1000, 200))

    def test_yields_all_batches(self, tmp_path):
        """Verify the generator yields batches from all sub-normalizers."""
        client = self._client_with_normalize_mocks()
        # 2 text files + 1 image
        for name in ["a.txt", "b.txt"]:
            (tmp_path / name).write_text("hi")
        (tmp_path / "c.png").write_bytes(b"\x89PNG")

        batches = list(client._normalize_files(
            [str(tmp_path / "a.txt"), str(tmp_path / "b.txt"), str(tmp_path / "c.png")],
            1000, 200,
        ))
        assert len(batches) == 3  # 1 per file


# ============================================================================
# Individual Normalizers (pure data transforms, no deeplake mocks needed)
# ============================================================================


class TestNormalizeImage:
    def test_returns_image_dict(self, tmp_path):
        client = _make_client()
        img_file = tmp_path / "photo.png"
        img_file.write_bytes(b"\x89PNG\r\n\x1a\n")

        with patch("uuid.uuid4", return_value="img-uuid"):
            result = client._normalize_image(img_file)

        assert result["file_id"] == ["img-uuid"]
        assert result["filename"] == ["photo.png"]
        assert result["image"] == [b"\x89PNG\r\n\x1a\n"]
        assert result["text"] == ["Image: photo.png"]
        assert result["id"] == ["img-uuid_0"]


class TestNormalizeText:
    def test_returns_text_dict(self, tmp_path):
        client = _make_client()
        txt_file = tmp_path / "doc.txt"
        txt_file.write_text("Hello world. This is a test document.", encoding="utf-8")

        with patch("uuid.uuid4", return_value="txt-uuid"):
            result = client._normalize_text(txt_file, chunk_size=1000, chunk_overlap=200)

        assert result["text"] == ["Hello world. This is a test document."]
        assert result["file_id"] == ["txt-uuid"]
        assert result["chunk_index"] == [0]
        assert result["id"] == ["txt-uuid_0"]

    def test_multiple_chunks(self, tmp_path):
        client = _make_client()
        txt_file = tmp_path / "long.txt"
        txt_file.write_text("A" * 500, encoding="utf-8")

        with patch("uuid.uuid4", return_value="txt-uuid"):
            result = client._normalize_text(txt_file, chunk_size=100, chunk_overlap=20)

        assert len(result["text"]) >= 2
        assert len(result["id"]) == len(result["text"])
        assert len(result["chunk_index"]) == len(result["text"])


class TestNormalizeBinary:
    def test_returns_binary_dict(self, tmp_path):
        client = _make_client()
        bin_file = tmp_path / "data.bin"
        bin_file.write_bytes(b"\xDE\xAD\xBE\xEF")

        with patch("uuid.uuid4", return_value="bin-uuid"):
            result = client._normalize_binary(bin_file)

        assert result["data"] == [b"\xDE\xAD\xBE\xEF"]
        assert result["filename"] == ["data.bin"]
        assert result["id"] == ["bin-uuid_0"]


class TestNormalizePdf:
    """Test PDF normalization when PyMuPDF (fitz) is not available."""

    def test_fallback_stores_whole_pdf(self, tmp_path):
        client = _make_client()
        pdf_file = tmp_path / "doc.pdf"
        pdf_content = b"%PDF-1.4 fake content"
        pdf_file.write_bytes(pdf_content)

        # Make fitz import fail
        import sys as _sys
        fitz_backup = _sys.modules.get("fitz")
        _sys.modules["fitz"] = None  # Force ImportError

        try:
            with patch("uuid.uuid4", return_value="pdf-uuid"):
                batches = list(client._normalize_pdf(pdf_file))
        finally:
            if fitz_backup is not None:
                _sys.modules["fitz"] = fitz_backup
            else:
                _sys.modules.pop("fitz", None)

        assert len(batches) == 1
        assert batches[0]["image"] == [pdf_content]
        assert batches[0]["text"] == ["PDF: doc.pdf"]
        assert batches[0]["id"] == ["pdf-uuid_0"]


class TestNormalizeVideo:
    """Test video normalization with mocked ffprobe/ffmpeg."""

    def test_zero_duration_yields_whole_file(self, tmp_path):
        client = _make_client()
        vid_file = tmp_path / "clip.mp4"
        vid_content = b"\x00\x00\x00\x1cftypisom"
        vid_file.write_bytes(vid_content)

        with patch("uuid.uuid4", return_value="vid-uuid"):
            with patch("subprocess.run", side_effect=Exception("ffprobe not found")):
                batches = list(client._normalize_video(vid_file))

        assert len(batches) == 1
        row = batches[0]
        assert row["id"] == ["vid-uuid_0"]
        assert row["video_data"] == [vid_content]
        assert row["start_time"] == [0.0]
        assert row["end_time"] == [0.0]

    def test_chunked_video(self, tmp_path):
        client = _make_client()
        vid_file = tmp_path / "long.mp4"
        vid_file.write_bytes(b"\x00" * 100)

        # ffprobe returns 25 second video -> 3 chunks at 10s interval
        probe_result = Mock()
        probe_result.stdout = json.dumps({"format": {"duration": "25.0"}})

        def subprocess_run_side_effect(cmd, **kwargs):
            if cmd[0] == "ffprobe":
                return probe_result
            if cmd[0] == "ffmpeg":
                # Create the output file so read_bytes works
                out_path = cmd[-1]
                Path(out_path).write_bytes(b"segment-data")
                return Mock()
            return Mock()

        with patch("uuid.uuid4", return_value="vid-uuid"):
            with patch("subprocess.run", side_effect=subprocess_run_side_effect):
                batches = list(client._normalize_video(vid_file))

        assert len(batches) == 3
        # Verify first chunk metadata
        assert batches[0]["chunk_index"] == [0]
        assert batches[0]["start_time"] == [0.0]
        assert batches[0]["end_time"] == [10.0]
        # Verify last chunk
