# _write_batches
# ============================================================================


class TestWriteBatches:
    def test_writes_batches_to_dataset(self):
        """Small batches are buffered and flushed together at the end."""
        client = _make_client()
        ds = FakeDataset()
        batches = [
            {"text": ["hello", "world"]},
            {"text": ["foo", "bar"]},
        ]

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            count = client._write_batches(ds, iter(batches), schema=None)

        assert count == 4
        # With default flush_every=200, both batches (4 rows total) stay in
        # the buffer and are flushed as a single ds.append() at the end.
        assert len(ds.appended) == 1
        assert ds.appended[0]["text"] == ["hello", "world", "foo", "bar"]

    def test_skips_empty_batches(self):
        client = _make_client()
        ds = FakeDataset()
        batches = [
            {"text": []},
            {"text": ["hello"]},
        ]

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            count = client._write_batches(ds, iter(batches), schema=None)

        assert count == 1
        assert len(ds.appended) == 1

    def test_calls_progress(self):
        """Progress is called once per flush; small batches buffer together."""
        client = _make_client()
        ds = FakeDataset()
        batches = [{"text": ["a", "b"]}, {"text": ["c"]}]
        calls = []

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            client._write_batches(
                ds, iter(batches), schema=None,
                on_progress=lambda c, t: calls.append((c, t)),
            )

        # All 3 rows buffered, flushed once at end → single progress call
        assert calls == [(3, -1)]

    def test_returns_total_row_count(self):
        client = _make_client()
        ds = FakeDataset()
        batches = [
            {"text": ["a", "b", "c"]},
            {"text": ["d"]},
        ]

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            count = client._write_batches(ds, iter(batches), schema=None)

        assert count == 4

    def test_flush_every_triggers_append(self):
        """When buffer hits flush_every, ds.append() is called mid-stream."""
        client = _make_client()
        ds = FakeDataset()
        batches = [
            {"text": ["a", "b"]},
            {"text": ["c", "d"]},
            {"text": ["e"]},
        ]

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            count = client._write_batches(
                ds, iter(batches), schema=None, flush_every=3,
            )

        assert count == 5
        # After batches 1+2 (4 rows >= 3), flush; batch 3 (1 row) flushed at end
        assert len(ds.appended) == 2
        assert ds.appended[0]["text"] == ["a", "b", "c", "d"]
        assert ds.appended[1]["text"] == ["e"]

    def test_periodic_commit(self):
        """ds.commit() is called when rows_since_commit >= commit_every."""
        client = _make_client()
        ds = FakeDataset()
        # 10 batches of 2 rows = 20 rows
        batches = [{"val": [i, i + 1]} for i in range(0, 20, 2)]

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            count = client._write_batches(
                ds, iter(batches), schema=None,
                flush_every=3, commit_every=6,
            )

        assert count == 20
        # commit() is called when rows_since_commit >= 6 after a flush
        assert ds.committed  # at least one commit happened

    def test_progress_called_per_flush(self):
        """on_progress fires after each flush, not after each batch."""
        client = _make_client()
        ds = FakeDataset()
        batches = [{"x": [i]} for i in range(7)]
        calls = []

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            client._write_batches(
                ds, iter(batches), schema=None,
                flush_every=3,
                on_progress=lambda c, t: calls.append((c, t)),
            )

        # 7 rows with flush_every=3: flush at 3, 6, then 1 remaining at end
        assert calls == [(3, -1), (6, -1), (7, -1)]

    def test_buffer_merges_columns(self):
        """Multiple batches with same columns are merged into one buffer."""
        client = _make_client()
        ds = FakeDataset()
        batches = [
            {"a": [1], "b": ["x"]},
            {"a": [2], "b": ["y"]},
        ]

        with patch.dict("sys.modules", {"deeplake": MagicMock(), "deeplake.types": MagicMock()}):
            count = client._write_batches(ds, iter(batches), schema=None)

        assert count == 2
        assert len(ds.appended) == 1
        assert ds.appended[0] == {"a": [1, 2], "b": ["x", "y"]}


