# ============================================================================


class TestParallelNormalizeFiles:
    """Verify _normalize_files uses thread pool for multiple files."""

    def test_single_file_no_pool(self, tmp_path):
        """Single file should bypass ThreadPoolExecutor."""
        client = _make_client()
        f = tmp_path / "a.txt"
        f.write_text("hello")
        client._normalize_one_file = Mock(return_value=[{"text": ["hello"]}])

        batches = list(client._normalize_files([str(f)], 1000, 200))
        assert len(batches) == 1
        client._normalize_one_file.assert_called_once()

    def test_multiple_files_use_pool(self, tmp_path):
        """Multiple files should use ThreadPoolExecutor."""
        client = _make_client()
        files = []
        for i in range(3):
            f = tmp_path / f"f{i}.txt"
            f.write_text(f"content {i}")
            files.append(str(f))

        client._normalize_one_file = Mock(
            side_effect=lambda fp, cs, co: [{"text": [f"from {fp}"]}]
        )

        batches = list(client._normalize_files(files, 1000, 200))
        assert len(batches) == 3
        assert client._normalize_one_file.call_count == 3

    def test_error_in_one_file_raises(self, tmp_path):
        """If one file fails in the pool, IngestError is raised."""
        client = _make_client()
        f1 = tmp_path / "good.txt"
        f1.write_text("ok")
        f2 = tmp_path / "bad.txt"
        f2.write_text("fail")

        def side_effect(fp, cs, co):
            if "bad" in fp:
                raise ValueError("processing failed")
            return [{"text": ["ok"]}]

        client._normalize_one_file = Mock(side_effect=side_effect)

        with pytest.raises(IngestError, match="Failed to process"):
            list(client._normalize_files([str(f1), str(f2)], 1000, 200))


