# ============================================================================
# Video per-segment temp cleanup
# ============================================================================


class TestVideoTempCleanup:
    def test_temp_dir_per_segment(self, tmp_path):
        """Each video segment should use its own temp directory."""
        client = _make_client()
        vid_file = tmp_path / "test.mp4"
        vid_file.write_bytes(b"\x00" * 100)

        # 15s video → 2 segments (0-10, 10-15)
        probe_result = Mock()
        probe_result.stdout = json.dumps({"format": {"duration": "15.0"}})

        temp_dirs_created = []

        original_tempdir = __import__("tempfile").TemporaryDirectory

        class TrackingTempDir:
            def __init__(self):
                self._real = original_tempdir()

            def __enter__(self):
                path = self._real.__enter__()
                temp_dirs_created.append(path)
                return path

            def __exit__(self, *args):
                return self._real.__exit__(*args)

        def subprocess_run_side_effect(cmd, **kwargs):
            if cmd[0] == "ffprobe":
                return probe_result
            if cmd[0] == "ffmpeg":
                out_path = cmd[-1]
                Path(out_path).write_bytes(b"segment")
                return Mock()
            return Mock()

        with patch("uuid.uuid4", return_value="vid-uuid"):
            with patch("subprocess.run", side_effect=subprocess_run_side_effect):
                with patch("tempfile.TemporaryDirectory", TrackingTempDir):
                    batches = list(client._normalize_video(vid_file))

        # Should create one temp dir per segment (not one shared temp dir)
        assert len(temp_dirs_created) == 2
        assert len(batches) == 2


