        from deeplake.managed import (
            Client,
            Database,
            ManagedQueryBuilder,
            ManagedServiceError,
            AuthError,
            CredentialsError,
            IngestError,
            TableError,
            TokenError,
            WorkspaceError,
        )

        assert Client is not None
        assert Database is not None
        assert ManagedQueryBuilder is not None
        assert TokenError is not None
        assert WorkspaceError is not None


