class TestFormatDispatch:
    """Verify ingest() dispatches to format.normalize() when format= is set."""

    def test_format_object_called(self):
        """ingest(format=obj) calls obj.normalize() and writes batches."""
        client = _make_client()
        client._root_path = "/data"
        client._create_table_via_api = Mock()

        fmt = Mock(spec=["normalize"])
        fmt.normalize.return_value = iter([{"x": [1, 2]}])

        mock_ds = MagicMock()
        mock_dl = MagicMock()
        mock_dl.exists.return_value = False
        mock_dl.create.return_value = mock_ds

        with patch.dict("sys.modules", {"deeplake": mock_dl, "deeplake.types": MagicMock()}):
            result = client.ingest("tbl", format=fmt)

        fmt.normalize.assert_called_once()
        assert result["row_count"] == 2

    def test_format_without_normalize_raises(self):
        """format= object without normalize() method raises IngestError."""
        client = _make_client()
        client._root_path = "/data"

        mock_dl = MagicMock()
        mock_dl.exists.return_value = False
        mock_dl.create.return_value = MagicMock()

        with patch.dict("sys.modules", {"deeplake": mock_dl}):
            with pytest.raises(IngestError, match="normalize"):
                client.ingest("tbl", format="not_an_object")

    def test_format_takes_precedence_over_data(self):
        """When both format= and data= are provided, format wins."""
        client = _make_client()
        client._root_path = "/data"
        client._create_table_via_api = Mock()

        fmt = Mock(spec=["normalize"])
        fmt.normalize.return_value = iter([{"from_format": [1]}])

        mock_ds = MagicMock()
        mock_dl = MagicMock()
        mock_dl.exists.return_value = False
        mock_dl.create.return_value = mock_ds

        with patch.dict("sys.modules", {"deeplake": mock_dl, "deeplake.types": MagicMock()}):
            result = client.ingest("tbl", {"ignored": [1]}, format=fmt)

        fmt.normalize.assert_called_once()
        assert result["row_count"] == 1

    def test_data_none_with_format_works(self):
        """ingest() works with data=None when format= is provided."""
        client = _make_client()
        client._root_path = "/data"
        client._create_table_via_api = Mock()

        fmt = Mock(spec=["normalize"])
        fmt.normalize.return_value = iter([{"col": [1, 2, 3]}])

        mock_ds = MagicMock()
        mock_dl = MagicMock()
        mock_dl.exists.return_value = False
        mock_dl.create.return_value = mock_ds

        with patch.dict("sys.modules", {"deeplake": mock_dl, "deeplake.types": MagicMock()}):
            result = client.ingest("tbl", format=fmt)

        assert result["row_count"] == 3


