def _make_coco_panoptic_fixture(tmp_path, num_images=3):
    """Create a minimal COCO panoptic dataset in tmp_path.

    Returns (images_dir, masks_dir, annotations_path).
    """
    images_dir = tmp_path / "images"
    masks_dir = tmp_path / "masks"
    images_dir.mkdir()
    masks_dir.mkdir()

    images = []
    annotations = []
    categories = [
        {"id": 1, "name": "person", "supercategory": "human"},
        {"id": 2, "name": "car", "supercategory": "vehicle"},
    ]

    for i in range(1, num_images + 1):
        img_name = f"{i:06d}.jpg"
        mask_name = f"{i:06d}.png"

        (images_dir / img_name).write_bytes(b"\xff\xd8\xff" + bytes([i]))
        (masks_dir / mask_name).write_bytes(b"\x89PNG" + bytes([i]))

        images.append({
            "id": i,
            "file_name": img_name,
            "width": 640,
            "height": 480,
        })
        annotations.append({
            "image_id": i,
            "file_name": mask_name,
            "segments_info": [
                {"id": i * 10, "category_id": 1, "area": 500 + i},
            ],
        })

    ann_path = tmp_path / "panoptic.json"
    ann_path.write_text(json.dumps({
        "images": images,
        "annotations": annotations,
        "categories": categories,
    }))

    return images_dir, masks_dir, ann_path


class TestCocoPanoptic:
    def test_normalize_yields_correct_columns(self, tmp_path):
        """Verify normalizer yields batches with the expected columns."""
        from .formats import CocoPanoptic

        images_dir, masks_dir, ann_path = _make_coco_panoptic_fixture(tmp_path)
        fmt = CocoPanoptic(
            images_dir=images_dir,
            masks_dir=masks_dir,
            annotations=ann_path,
        )

        batches = list(fmt.normalize())
        assert len(batches) == 1  # 3 images < default batch_size=100

        batch = batches[0]
        expected_cols = {
            "coco_image_id", "image", "mask", "width", "height",
            "filename", "mask_filename", "segments_info", "categories",
        }
        assert set(batch.keys()) == expected_cols
        assert len(batch["coco_image_id"]) == 3

    def test_normalize_values(self, tmp_path):
        """Verify actual column values for a single image."""
        from .formats import CocoPanoptic

        images_dir, masks_dir, ann_path = _make_coco_panoptic_fixture(
            tmp_path, num_images=1,
        )
        fmt = CocoPanoptic(
            images_dir=images_dir,
            masks_dir=masks_dir,
            annotations=ann_path,
        )

        batches = list(fmt.normalize())
        batch = batches[0]

        assert batch["coco_image_id"] == [1]
        assert batch["image"] == [b"\xff\xd8\xff\x01"]
        assert batch["mask"] == [b"\x89PNG\x01"]
        assert batch["width"] == [640]
        assert batch["height"] == [480]
        assert batch["filename"] == ["000001.jpg"]

        segments = json.loads(batch["segments_info"][0])
        assert len(segments) == 1
        assert segments[0]["category_id"] == 1

        categories = json.loads(batch["categories"][0])
        assert len(categories) == 2
        assert categories[0]["name"] == "person"

    def test_normalize_batching(self, tmp_path):
        """Verify batches respect batch_size."""
        from .formats import CocoPanoptic

        images_dir, masks_dir, ann_path = _make_coco_panoptic_fixture(
            tmp_path, num_images=5,
        )
        fmt = CocoPanoptic(
            images_dir=images_dir,
            masks_dir=masks_dir,
            annotations=ann_path,
            batch_size=2,
        )

        batches = list(fmt.normalize())
        assert len(batches) == 3  # 2 + 2 + 1
        assert len(batches[0]["coco_image_id"]) == 2
        assert len(batches[1]["coco_image_id"]) == 2
        assert len(batches[2]["coco_image_id"]) == 1

    def test_skips_missing_images(self, tmp_path):
        """Images referenced in JSON but not on disk are skipped."""
        from .formats import CocoPanoptic

        images_dir, masks_dir, ann_path = _make_coco_panoptic_fixture(
            tmp_path, num_images=3,
        )
        # Delete one image file
        (images_dir / "000002.jpg").unlink()

        fmt = CocoPanoptic(
            images_dir=images_dir,
            masks_dir=masks_dir,
            annotations=ann_path,
        )

        batches = list(fmt.normalize())
        all_ids = [
            img_id for b in batches for img_id in b["coco_image_id"]
        ]
        assert 2 not in all_ids
        assert len(all_ids) == 2

    def test_skips_missing_annotations(self, tmp_path):
        """Images without annotations are skipped."""
        from .formats import CocoPanoptic

        images_dir = tmp_path / "images"
        masks_dir = tmp_path / "masks"
