# K1: Configurable query timeout
# ============================================================================


class TestQueryTimeout:
    """Tests for configurable query timeout (K1).

    Issue: The 60s hardcoded timeout caused large queries to silently fail.
    Fix: Added ``timeout`` parameter to ``client.query()``.
    """

    def test_default_timeout_is_60(self):
        """Default timeout remains 60s for backward compatibility."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["id"], "rows": [["r1"]], "row_count": 1,
        })

        client.query("SELECT 1")
        client._api_request.assert_called_once_with(
            "POST",
            "/workspaces/test-ws/tables/query",
            json_data={"query": "SELECT 1"},
            timeout=60,
        )

    def test_custom_timeout_forwarded(self):
        """Custom timeout is forwarded to _api_request."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["id"], "rows": [["r1"]], "row_count": 1,
        })

        client.query("SELECT COUNT(*) FROM big", timeout=300)
        client._api_request.assert_called_once_with(
            "POST",
            "/workspaces/test-ws/tables/query",
            json_data={"query": "SELECT COUNT(*) FROM big", "timeout_ms": 300000},
            timeout=300,
        )

    def test_default_timeout_no_timeout_ms_in_body(self):
        """Default timeout (60) does NOT send timeout_ms to avoid noise."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": [], "rows": [], "row_count": 0,
        })

        client.query("SELECT 1")
        body = client._api_request.call_args[1].get("json_data") or client._api_request.call_args[0][2]
        assert "timeout_ms" not in body


