class TestPdfDpi:
    """Tests for configurable PDF DPI (K4).

    Issue: 300 DPI rendering was 3.5x slower than 150 DPI with no user control.
    Fix: Added ``dpi`` parameter to ``_normalize_pdf()`` with default 150.
    """

    def test_default_dpi_is_150(self):
        """Default DPI produces smaller images than 300 DPI."""
        fitz = pytest.importorskip("fitz")

        import tempfile
        doc = fitz.open()
        page = doc.new_page(width=200, height=200)
        tw = fitz.TextWriter(page.rect)
        tw.append((50, 100), "test", fontsize=14)
        tw.write_text(page)
        path = Path(tempfile.mktemp(suffix=".pdf"))
        doc.save(str(path))
        doc.close()

        client = _make_client()

        # Default (150 DPI)
        batches_150 = list(client._normalize_pdf(path))
        img_150 = batches_150[0]["image"][0]

        # Explicit 300 DPI
        batches_300 = list(client._normalize_pdf(path, dpi=300))
        img_300 = batches_300[0]["image"][0]

        # 150 DPI should produce a smaller image than 300 DPI
        assert len(img_150) < len(img_300), (
            f"150 DPI image ({len(img_150)} bytes) should be smaller "
            f"than 300 DPI image ({len(img_300)} bytes)"
        )

        path.unlink(missing_ok=True)

    def test_custom_dpi_72(self):
        """72 DPI produces even smaller images."""
        fitz = pytest.importorskip("fitz")

        import tempfile
        doc = fitz.open()
        page = doc.new_page(width=200, height=200)
        tw = fitz.TextWriter(page.rect)
        tw.append((50, 100), "test", fontsize=14)
        tw.write_text(page)
        path = Path(tempfile.mktemp(suffix=".pdf"))
        doc.save(str(path))
        doc.close()

        client = _make_client()

        batches_72 = list(client._normalize_pdf(path, dpi=72))
        batches_150 = list(client._normalize_pdf(path, dpi=150))

        assert len(batches_72[0]["image"][0]) < len(batches_150[0]["image"][0])

        path.unlink(missing_ok=True)

    def test_dpi_threaded_through_normalize_one_file(self):
        """pdf_dpi parameter is forwarded through _normalize_one_file."""
        fitz = pytest.importorskip("fitz")

        import tempfile
        doc = fitz.open()
        page = doc.new_page(width=200, height=200)
        tw = fitz.TextWriter(page.rect)
        tw.append((50, 100), "test", fontsize=14)
        tw.write_text(page)
        path = Path(tempfile.mktemp(suffix=".pdf"))
        doc.save(str(path))
        doc.close()

        client = _make_client()

        batches_72 = client._normalize_one_file(str(path), 1000, 200, pdf_dpi=72)
        batches_300 = client._normalize_one_file(str(path), 1000, 200, pdf_dpi=300)

        assert len(batches_72[0]["image"][0]) < len(batches_300[0]["image"][0])

        path.unlink(missing_ok=True)

    def test_150_dpi_faster_than_300(self):
        """150 DPI renders faster than 300 DPI (performance regression guard)."""
        fitz = pytest.importorskip("fitz")

        import tempfile, time
        doc = fitz.open()
        for _ in range(5):
            page = doc.new_page(width=612, height=792)
            tw = fitz.TextWriter(page.rect)
            for line in range(10):
                tw.append((72, 72 + line * 30), f"Line {line}", fontsize=12)
            tw.write_text(page)
        path = Path(tempfile.mktemp(suffix=".pdf"))
        doc.save(str(path))
        doc.close()

        client = _make_client()

        t0 = time.perf_counter()
        list(client._normalize_pdf(path, dpi=150))
        t_150 = time.perf_counter() - t0

        t0 = time.perf_counter()
        list(client._normalize_pdf(path, dpi=300))
        t_300 = time.perf_counter() - t0

        # 150 DPI should be at least 1.5x faster
        assert t_150 < t_300, (
            f"150 DPI ({t_150:.3f}s) should be faster than 300 DPI ({t_300:.3f}s)"
        )

        path.unlink(missing_ok=True)


