# ============================================================================


class TestParallelThumbnails:
    """Tests for parallel thumbnail generation.

    Issue: Serial thumbnail generation was a bottleneck for image-heavy ingests.
    Fix: ThreadPoolExecutor(max_workers=4) with executor.map().
    """

    def test_thumbnails_correct_count(self):
        """Parallel thumbnails produce the same count as input images."""
        PIL = pytest.importorskip("PIL")
        from PIL import Image as PILImage
        import io

        images = []
        for i in range(10):
            img = PILImage.new("RGB", (256, 256), color=(i * 25, 0, 0))
            buf = io.BytesIO()
            img.save(buf, format="JPEG")
            images.append(buf.getvalue())

        buffer = {"image": images}
        Client._generate_inline_thumbnails(buffer, ["image"])

        assert "image_thumbnail" in buffer
        assert len(buffer["image_thumbnail"]) == 10
        # All thumbnails should be non-empty JPEG bytes
        for thumb in buffer["image_thumbnail"]:
            assert isinstance(thumb, bytes)
            assert len(thumb) > 0

    def test_thumbnails_are_smaller(self):
        """Generated thumbnails are smaller than originals."""
        PIL = pytest.importorskip("PIL")
        from PIL import Image as PILImage
        import io

        img = PILImage.new("RGB", (1024, 1024), color=(128, 64, 32))
        buf = io.BytesIO()
        img.save(buf, format="JPEG", quality=95)
        original = buf.getvalue()

        buffer = {"image": [original]}
        Client._generate_inline_thumbnails(buffer, ["image"])

        thumb = buffer["image_thumbnail"][0]
        assert len(thumb) < len(original), "Thumbnail should be smaller than original"

    def test_thumbnails_handle_bad_data(self):
        """Bad image data produces empty bytes placeholder, not an error."""
        buffer = {"image": [b"not an image", b"", b"\x00\x01\x02"]}
        Client._generate_inline_thumbnails(buffer, ["image"])

        assert len(buffer["image_thumbnail"]) == 3
        # Bad images get empty bytes
        assert buffer["image_thumbnail"][0] == b""
        assert buffer["image_thumbnail"][1] == b""
        assert buffer["image_thumbnail"][2] == b""
